            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
            long ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);

            int32_t *bias2 = (int32_t *)bias;

            for (long i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
            {
                long i_ch_mult = 0;
                int ch_mult_rest = ch_mult;
                for (; i_ch_mult < ch_mult; i_ch_mult += vl)
                {
                    long idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE32_V(NDS_VEC_V0, bias2);
                    bias2 += vl;

                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
                    for (long i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
                    {
                        long idx_y = base_idx_y + i_ker_y;
                        long ker_idx_0 = (i_ker_y * ker_dim_x + ker_x_start) * (in_tensor_ch * ch_mult) + idx_out_ch;
                        uint8_t *kernel_ptr = (uint8_t *)&ker_weight[ker_idx_0];

                        long idx_x = base_idx_x + ker_x_start;
                        long idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
                        uint8_t *in_ptr = (uint8_t *)&in_tensor[idx_0];
                        long i_ker_x;
                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
                        {
                            long in = *in_ptr + in_offset;
                            NDS_VEC_VLE8_V(NDS_VEC_V12, kernel_ptr);
                            NDS_VEC_VZEXT_VF2(NDS_VEC_V8, NDS_VEC_V12);
                            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, ker_offset);
                            NDS_VEC_VWMACC_VX(NDS_VEC_V0, in, NDS_VEC_V8);
                            in_ptr += in_tensor_ch;
                            kernel_ptr += in_tensor_ch * ch_mult;
                        }
                    }

                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

                    //requantization
                    //part-1
                    long vl2;
                    NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
                    NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V0, out_scale);
                    NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
                    NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);

                    NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
                    NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
                    NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);

                    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
                    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
                    NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
                    ch_mult_rest -= vl2;
                    out_tensor += vl2;

                    //part-2
                    if(ch_mult_rest > 0)
                    {
                        NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V4, out_scale);
                        NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
                        NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);

                        NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
                        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
                        NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);

                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
                        NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
                        ch_mult_rest -= vl2;
                        out_tensor += vl2;
                    }
                }
            }
        }
    }
